1	// Acceptance mutation engine. Port of gospringies'
2	// `internal/acceptancemutation/mutator.go`, retargeted onto the #113 Gherkin
3	// IR + #114 generator slice.
4	//
5	// Walks Example cells, applies one typed mutation per cell, runs the mutated
6	// feature in-process, and classifies killed / survived / error. RNG is
7	// internally deterministic (same input always mutates the same way) but is
8	// NOT byte-identical to Go's math/rand — cross-repo parity is out of scope.
9	//
10	// Workerd-safe by construction: no node:fs / node:os / node:crypto /
11	// child_process. The sha256 below is a self-contained sync implementation so
12	// `mutateValue` stays synchronous and this whole module is unit-testable
13	// inside the vitest-pool-workers pool. The node CLI lives at
14	// `scripts/mutation-gherkin.ts`.
15	
16	import type { Feature } from "./feature-ir";
17	import { runFeatureWith } from "./feature-runner";
18	import type { StepRegistry } from "./feature-step-adapter";
19	
20	// ── Mutation model ──────────────────────────────────────────────────────────
21	
22	export type Mutation = {
23	  id: string;
24	  path: string;
25	  description: string;
26	  original: string;
27	  mutated: string;
28	  scenario: number;
29	  example: number;
30	  key: string;
31	};
32	
33	export const MUTATION_KILLED = "killed";
34	export const MUTATION_SURVIVED = "survived";
35	export const MUTATION_ERROR = "error";
36	export type MutationStatus =
37	  | typeof MUTATION_KILLED
38	  | typeof MUTATION_SURVIVED
39	  | typeof MUTATION_ERROR;
40	
41	export type MutationResult = {
42	  mutation: Mutation;
43	  status: MutationStatus;
44	  error?: string;
45	  durationMs: number;
46	};
47	
48	export type MutationSummary = {
49	  total: number;
50	  killed: number;
51	  survived: number;
52	  error: number;
53	};
54	
55	export type MutationProgress = {
56	  completed: number;
57	  total: number;
58	  killed: number;
59	  survived: number;
60	  error: number;
61	};
62	
63	// ── Build ─────────────────────────────────────────────────────────────────
64	
65	export function buildMutations(feature: Feature): Mutation[] {
66	  const mutations: Mutation[] = [];
67	  feature.scenarios.forEach((scenario, scenarioIndex) => {
68	    scenario.examples.forEach((example, exampleIndex) => {
69	      const keys = Object.keys(example).sort();
70	      for (const key of keys) {
71	        const mutation = buildMutation(
72	          feature,
73	          scenarioIndex,
74	          exampleIndex,
75	          key,
76	          example[key] ?? "",
77	          mutations.length + 1,
78	        );
79	        if (mutation !== null) mutations.push(mutation);
80	      }
81	    });
82	  });
83	  return mutations;
84	}
85	
86	function buildMutation(
87	  feature: Feature,
88	  scenarioIndex: number,
89	  exampleIndex: number,
90	  key: string,
91	  original: string,
92	  idNumber: number,
93	): Mutation | null {
94	  const path = `$.scenarios[${scenarioIndex}].examples[${exampleIndex}].${key}`;
95	  const mutated = mutateValue(path, original);
96	  if (mutated === original || isEquivalentMutation(feature, scenarioIndex, exampleIndex, key)) {
97	    return null;
98	  }
99	  return {
100	    id: `m${idNumber}`,
101	    path,
102	    description: `${path}: ${original} -> ${mutated}`,
103	    original,
104	    mutated,
105	    scenario: scenarioIndex,
106	    example: exampleIndex,
107	    key,
108	  };
109	}
110	
111	// ── Equivalence-pruning hook ────────────────────────────────────────────────
112	//
113	// Feature-name-keyed registry mirroring gospringies' `equivalentMutationChecks`
114	// map. A rule returns `true` for an (scenario, example, key) cell that should
115	// be SKIPPED — typically a cell used as both setup data and the asserted value,
116	// where mutating both sides preserves the observed behaviour (a "null" mutant).
117	//
118	// Empty by default. Add per-feature rules as real equivalent mutants surface.
119	// Use `scenarioOnlyEquivalentCheck` when the rule ignores the example index.
120	//
121	//   equivalentMutationChecks["My feature"] = scenarioOnlyEquivalentCheck(
122	//     (scenarioIndex, key) => scenarioIndex === 2 && key === "lookup_id",
123	//   );
124	
125	export type EquivalentMutationCheck = (
126	  scenarioIndex: number,
127	  exampleIndex: number,
128	  key: string,
129	) => boolean;
130	
131	export const equivalentMutationChecks: Record<string, EquivalentMutationCheck> = {};
132	
133	export function isEquivalentMutation(
134	  feature: Feature,
135	  scenarioIndex: number,
136	  exampleIndex: number,
137	  key: string,
138	): boolean {
139	  const check = equivalentMutationChecks[feature.name];
140	  return check?.(scenarioIndex, exampleIndex, key) ?? false;
141	}
142	
143	export function scenarioOnlyEquivalentCheck(
144	  check: (scenarioIndex: number, key: string) => boolean,
145	): EquivalentMutationCheck {
146	  return (scenarioIndex, _exampleIndex, key) => check(scenarioIndex, key);
147	}
148	
149	// ── Operators ───────────────────────────────────────────────────────────────
150	
151	// Operators tried in order; the first to return non-null wins. Each takes the
152	// trimmed value, the original (for dither fallbacks), and the seeded RNG.
153	type Operator = (trimmed: string, original: string, rng: Rng) => string | null;
154	
155	const OPERATORS: Operator[] = [mutateKeyword, mutateNumber, mutateDate, mutateDuration];
156	
157	export function mutateValue(path: string, value: string): string {
158	  const trimmed = value.trim();
159	  const rng = deterministicRng(path, value);
160	  if (trimmed.includes(",")) return mutateList(path, trimmed, rng);
161	  for (const operator of OPERATORS) {
162	    const mutated = operator(trimmed, value, rng);
163	    if (mutated !== null) return mutated;
164	  }
165	  return dither(value, rng);
166	}
167	
168	function mutateList(path: string, value: string, rng: Rng): string {
169	  const parts = value.split(",");
170	  const index = rng.intn(parts.length);
171	  const target = (parts[index] ?? "").trim();
172	  parts[index] = mutateValue(`${path}[${index}]`, target);
173	  return parts.map((part) => part.trim()).join(", ");
174	}
175	
176	const BOOLEAN_FLIP: Record<string, string> = { true: "false", false: "true" };
177	const NULL_KEYWORDS = new Set(["null", "nil", "none"]);
178	
179	function mutateKeyword(trimmed: string, original: string, rng: Rng): string | null {
180	  const lower = trimmed.toLowerCase();
181	  const flipped = BOOLEAN_FLIP[lower];
182	  if (flipped !== undefined) return flipped;
183	  if (NULL_KEYWORDS.has(lower)) return dither(original, rng);
184	  return null;
185	}
186	
187	function mutateNumber(value: string, _original: string, rng: Rng): string | null {
188	  if (/^[+-]?\d+$/.test(value)) {
189	    return String(Number.parseInt(value, 10) + signedIntDelta(rng));
190	  }
191	  if (!/[.eE]/.test(value)) return null;
192	  const f = Number.parseFloat(value);
193	  if (!Number.isFinite(f)) return null;
194	  return formatFloat(f + signedFloatDelta(rng));
195	}
196	
197	function signedIntDelta(rng: Rng): number {
198	  const delta = rng.intn(9) + 1;
199	  return rng.intn(2) === 0 ? -delta : delta;
200	}
201	
202	function signedFloatDelta(rng: Rng): number {
203	  const delta = (rng.intn(900) + 100) / 100;
204	  return rng.intn(2) === 0 ? -delta : delta;
205	}
206	
207	// Shortest decimal without an exponent, with fp noise stripped. Mirrors Go's
208	// FormatFloat(f, 'f', -1, 64) closely enough for example-cell magnitudes.
209	function formatFloat(n: number): string {
210	  const fixed = n.toFixed(10).replace(/0+$/, "").replace(/\.$/, "");
211	  return fixed === "-0" ? "0" : fixed;
212	}
213	
214	const DATE_RE = /^(\d{4})-(\d{2})-(\d{2})$/;
215	
216	function mutateDate(value: string, _original: string, rng: Rng): string | null {
217	  const match = DATE_RE.exec(value);
218	  if (match === null) return null;
219	  const date = parseUtcYmd(Number(match[1]), Number(match[2]), Number(match[3]));
220	  if (date === null) return null;
221	  date.setUTCDate(date.getUTCDate() + signedIntDelta(rng));
222	  return formatUtcDate(date);
223	}
224	
225	// Reject impossible calendar dates (Go's time.Parse is strict).
226	function parseUtcYmd(year: number, month: number, day: number): Date | null {
227	  const date = new Date(Date.UTC(year, month - 1, day));
228	  const valid =
229	    date.getUTCFullYear() === year && date.getUTCMonth() === month - 1 && date.getUTCDate() === day;
230	  return valid ? date : null;
231	}
232	
233	function formatUtcDate(date: Date): string {
234	  const y = String(date.getUTCFullYear()).padStart(4, "0");
235	  const m = String(date.getUTCMonth() + 1).padStart(2, "0");
236	  const d = String(date.getUTCDate()).padStart(2, "0");
237	  return `${y}-${m}-${d}`;
238	}
239	
240	function mutateDuration(value: string, _original: string, rng: Rng): string | null {
241	  const ns = parseGoDuration(value);
242	  if (ns === null) return null;
243	  const added = ns + (rng.intn(9) + 1) * 1e9;
244	  return formatGoDuration(added);
245	}
246	
247	function dither(value: string, rng: Rng): string {
248	  if (value === "") return "x";
249	  const runes = [...value];
250	  const index = rng.intn(runes.length);
251	  runes[index] = runes[index] === "x" ? "y" : "x";
252	  return runes.join("");
253	}
254	
255	// ── Go duration parse / format (subset) ──────────────────────────────────────
256	
257	const DURATION_UNITS: Record<string, number> = {
258	  ns: 1,
259	  us: 1e3,
260	  µs: 1e3,
261	  μs: 1e3,
262	  ms: 1e6,
263	  s: 1e9,
264	  m: 60e9,
265	  h: 3600e9,
266	};
267	
268	function parseGoDuration(input: string): number | null {
269	  const { neg, rest } = parseSign(input);
270	  const ns = parseDurationBody(rest);
271	  if (ns === null) return null;
272	  return neg ? -ns : ns;
273	}
274	
275	function parseSign(s: string): { neg: boolean; rest: string } {
276	  if (s.startsWith("+") || s.startsWith("-")) {
277	    return { neg: s[0] === "-", rest: s.slice(1) };
278	  }
279	  return { neg: false, rest: s };
280	}
281	
282	function parseDurationBody(input: string): number | null {
283	  let s = input;
284	  if (s === "") return null;
285	  let total = 0;
286	  while (s !== "") {
287	    const segment = parseDurationSegment(s);
288	    if (segment === null) return null;
289	    total += segment.ns;
290	    s = segment.rest;
291	  }
292	  return total;
293	}
294	
295	function parseDurationSegment(s: string): { ns: number; rest: string } | null {
296	  // `/^[0-9]*\.?[0-9]*/` always matches (possibly empty) → exec never null.
297	  const numStr = (/^[0-9]*\.?[0-9]*/.exec(s) as RegExpExecArray)[0];
298	  if (numStr === "" || numStr === ".") return null;
299	  const afterNum = s.slice(numStr.length);
300	  const unitMatch = /^(ns|us|µs|μs|ms|s|m|h)/.exec(afterNum);
301	  if (unitMatch === null) return null;
302	  const unit = unitMatch[1] as string;
303	  return {
304	    ns: Number.parseFloat(numStr) * (DURATION_UNITS[unit] as number),
305	    rest: afterNum.slice(unit.length),
306	  };
307	}
308	
309	// Mutations only ever ADD whole seconds, so a mutated duration's magnitude is
310	// always ≥ 1s (sub-second results would need contrived negative inputs). We
311	// therefore format in the s / m / h range only; a rare sub-second magnitude
312	// renders as a fractional-second form ("0.5s"), which is still a valid Go
313	// duration string. Sub-second unit selection (ns/µs/ms) is intentionally
314	// omitted — it is unreachable from `mutateDuration`.
315	function formatGoDuration(ns: number): string {
316	  const neg = ns < 0;
317	  const u = Math.round(Math.abs(ns));
318	  if (u === 0) return "0s";
319	  return (neg ? "-" : "") + formatSeconds(u);
320	}
321	
322	function formatSeconds(u: number): string {
323	  const frac = fmtFrac(u, 9);
324	  let rem = frac.value;
325	  let out = `${fmtInt(rem % 60)}${frac.text}s`;
326	  rem = Math.floor(rem / 60);
327	  if (rem > 0) {
328	    out = `${fmtInt(rem % 60)}m${out}`;
329	    rem = Math.floor(rem / 60);
330	    if (rem > 0) out = `${fmtInt(rem)}h${out}`;
331	  }
332	  return out;
333	}
334	
335	function fmtFrac(value: number, prec: number): { text: string; value: number } {
336	  let v = value;
337	  const digits: number[] = [];
338	  for (let i = 0; i < prec; i++) {
339	    digits.push(v % 10);
340	    v = Math.floor(v / 10);
341	  }
342	  return { text: fracText(digits), value: v };
343	}
344	
345	// `digits` is least-significant-first; drop the least-significant zeros, then
346	// render most-significant-first behind a decimal point (empty if all zero).
347	function fracText(digits: number[]): string {
348	  let start = 0;
349	  while (start < digits.length && digits[start] === 0) start += 1;
350	  if (start === digits.length) return "";
351	  return `.${digits.slice(start).reverse().join("")}`;
352	}
353	
354	function fmtInt(value: number): string {
355	  if (value === 0) return "0";
356	  let v = value;
357	  let text = "";
358	  while (v > 0) {
359	    text = String(v % 10) + text;
360	    v = Math.floor(v / 10);
361	  }
362	  return text;
363	}
364	
365	// ── Deterministic RNG: sha256(parts) → 32-bit seed → mulberry32 ──────────────
366	
367	type Rng = { intn: (n: number) => number };
368	
369	export function deterministicRng(...parts: string[]): Rng {
370	  const digest = sha256(parts.join("�"));
371	  // First 4 bytes, big-endian, as the mulberry32 seed.
372	  const seed =
373	    ((digest[0] as number) << 24) |
374	    ((digest[1] as number) << 16) |
375	    ((digest[2] as number) << 8) |
376	    (digest[3] as number);
377	  const next = mulberry32(seed >>> 0);
378	  return {
379	    intn: (n: number) => (n <= 0 ? 0 : Math.floor(next() * n)),
380	  };
381	}
382	
383	function mulberry32(seed: number): () => number {
384	  let a = seed >>> 0;
385	  return () => {
386	    a = (a + 0x6d2b79f5) | 0;
387	    let t = Math.imul(a ^ (a >>> 15), 1 | a);
388	    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
389	    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
390	  };
391	}
392	
393	// Self-contained synchronous SHA-256 (no node:crypto / SubtleCrypto), so the
394	// engine stays sync + workerd-safe. Returns the 32-byte digest.
395	const SHA256_K = new Uint32Array([
396	  0x428a2f98, 0x71374491, 0xb5c0fbcf, 0xe9b5dba5, 0x3956c25b, 0x59f111f1, 0x923f82a4, 0xab1c5ed5,
397	  0xd807aa98, 0x12835b01, 0x243185be, 0x550c7dc3, 0x72be5d74, 0x80deb1fe, 0x9bdc06a7, 0xc19bf174,
398	  0xe49b69c1, 0xefbe4786, 0x0fc19dc6, 0x240ca1cc, 0x2de92c6f, 0x4a7484aa, 0x5cb0a9dc, 0x76f988da,
399	  0x983e5152, 0xa831c66d, 0xb00327c8, 0xbf597fc7, 0xc6e00bf3, 0xd5a79147, 0x06ca6351, 0x14292967,
400	  0x27b70a85, 0x2e1b2138, 0x4d2c6dfc, 0x53380d13, 0x650a7354, 0x766a0abb, 0x81c2c92e, 0x92722c85,
401	  0xa2bfe8a1, 0xa81a664b, 0xc24b8b70, 0xc76c51a3, 0xd192e819, 0xd6990624, 0xf40e3585, 0x106aa070,
402	  0x19a4c116, 0x1e376c08, 0x2748774c, 0x34b0bcb5, 0x391c0cb3, 0x4ed8aa4a, 0x5b9cca4f, 0x682e6ff3,
403	  0x748f82ee, 0x78a5636f, 0x84c87814, 0x8cc70208, 0x90befffa, 0xa4506ceb, 0xbef9a3f7, 0xc67178f2,
404	]);
405	
406	const SHA256_INIT = [
407	  0x6a09e667, 0xbb67ae85, 0x3c6ef372, 0xa54ff53a, 0x510e527f, 0x9b05688c, 0x1f83d9ab, 0x5be0cd19,
408	];
409	
410	function sha256(message: string): Uint8Array {
411	  const padded = padMessage(new TextEncoder().encode(message));
412	  const dv = new DataView(padded.buffer);
413	  const state = Uint32Array.from(SHA256_INIT);
414	  for (let offset = 0; offset < padded.length; offset += 64) {
415	    compressBlock(state, dv, offset);
416	  }
417	  return stateToBytes(state);
418	}
419	
420	function padMessage(bytes: Uint8Array): Uint8Array {
421	  const bitLen = bytes.length * 8;
422	  const withOne = bytes.length + 1;
423	  const total = withOne + ((56 - (withOne % 64) + 64) % 64) + 8;
424	  const padded = new Uint8Array(total);
425	  padded.set(bytes);
426	  padded[bytes.length] = 0x80;
427	  // 64-bit big-endian length; high word is 0 for our small inputs.
428	  const dv = new DataView(padded.buffer);
429	  dv.setUint32(total - 4, bitLen >>> 0, false);
430	  dv.setUint32(total - 8, Math.floor(bitLen / 0x100000000), false);
431	  return padded;
432	}
433	
434	function computeSchedule(dv: DataView, offset: number): Uint32Array {
435	  const w = new Uint32Array(64);
436	  for (let i = 0; i < 16; i++) w[i] = dv.getUint32(offset + i * 4, false);
437	  for (let i = 16; i < 64; i++) {
438	    const x = w[i - 15] as number;
439	    const y = w[i - 2] as number;
440	    const s0 = rotr(x, 7) ^ rotr(x, 18) ^ (x >>> 3);
441	    const s1 = rotr(y, 17) ^ rotr(y, 19) ^ (y >>> 10);
442	    w[i] = ((w[i - 16] as number) + s0 + (w[i - 7] as number) + s1) | 0;
443	  }
444	  return w;
445	}
446	
447	function compressBlock(state: Uint32Array, dv: DataView, offset: number): void {
448	  const w = computeSchedule(dv, offset);
449	  let a = state[0] as number;
450	  let b = state[1] as number;
451	  let c = state[2] as number;
452	  let d = state[3] as number;
453	  let e = state[4] as number;
454	  let f = state[5] as number;
455	  let g = state[6] as number;
456	  let hh = state[7] as number;
457	  for (let i = 0; i < 64; i++) {
458	    const s1 = rotr(e, 6) ^ rotr(e, 11) ^ rotr(e, 25);
459	    const ch = (e & f) ^ (~e & g);
460	    const t1 = (hh + s1 + ch + (SHA256_K[i] as number) + (w[i] as number)) | 0;
461	    const s0 = rotr(a, 2) ^ rotr(a, 13) ^ rotr(a, 22);
462	    const maj = (a & b) ^ (a & c) ^ (b & c);
463	    const t2 = (s0 + maj) | 0;
464	    hh = g;
465	    g = f;
466	    f = e;
467	    e = (d + t1) | 0;
468	    d = c;
469	    c = b;
470	    b = a;
471	    a = (t1 + t2) | 0;
472	  }
473	  const next = [a, b, c, d, e, f, g, hh];
474	  for (let i = 0; i < 8; i++) state[i] = ((state[i] as number) + (next[i] as number)) | 0;
475	}
476	
477	function stateToBytes(state: Uint32Array): Uint8Array {
478	  const out = new Uint8Array(32);
479	  const outView = new DataView(out.buffer);
480	  for (let i = 0; i < 8; i++) outView.setUint32(i * 4, state[i] as number, false);
481	  return out;
482	}
483	
484	function rotr(x: number, n: number): number {
485	  return (x >>> n) | (x << (32 - n));
486	}
487	
488	// ── In-process runner ─────────────────────────────────────────────────────
489	
490	// Thrown by the run hook for a generator/harness crash → classified `error`.
491	// Any other throw (failed assertion, missing step, timeout) → `killed`.
492	export class MutationRunError extends Error {}
493	
494	export type RunFeatureFn<E> = (
495	  feature: Feature,
496	  env: E,
497	  registry: StepRegistry<E>,
498	) => Promise<void>;
499	
500	export type RunMutationsOptions<E> = {
501	  registry: StepRegistry<E>;
502	  env: E;
503	  workers?: number;
504	  mutantTimeoutMs?: number;
505	  globalTimeoutMs?: number;
506	  progressEvery?: number;
507	  onProgress?: (progress: MutationProgress) => void;
508	  runFeature?: RunFeatureFn<E>;
509	  now?: () => number;
510	  skipPaths?: ReadonlySet<string>;
511	};
512	
513	type ResolvedRun<E> = {
514	  now: () => number;
515	  runFeature: RunFeatureFn<E>;
516	  workerCount: number;
517	  deadline: number;
518	};
519	
520	export async function runMutations<E>(
521	  feature: Feature,
522	  options: RunMutationsOptions<E>,
523	): Promise<MutationResult[]> {
524	  const allMutations = buildMutations(feature);
525	  const skipPaths = options.skipPaths;
526	  if (!skipPaths?.size) {
527	    const results: MutationResult[] = [];
528	    const config = resolveRun(options, allMutations.length);
529	    const tracker = new ProgressTracker(
530	      allMutations.length,
531	      options.progressEvery,
532	      options.onProgress,
533	    );
534	    await drainWorkers(feature, allMutations, results, options, config, tracker);
535	    return results;
536	  }
537	  const toRun = allMutations.filter((m) => !skipPaths.has(m.path));
538	  const runResults: MutationResult[] = [];
539	  const config = resolveRun(options, toRun.length);
540	  const tracker = new ProgressTracker(toRun.length, options.progressEvery, options.onProgress);
541	  await drainWorkers(feature, toRun, runResults, options, config, tracker);
542	  let runIdx = 0;
543	  return allMutations.map((m) =>
544	    skipPaths.has(m.path)
545	      ? { mutation: m, status: MUTATION_KILLED, durationMs: 0 }
546	      : (runResults[runIdx++] as MutationResult),
547	  );
548	}
549	
550	function resolveRun<E>(options: RunMutationsOptions<E>, count: number): ResolvedRun<E> {
551	  const now = options.now ?? (() => Date.now());
552	  return {
553	    now,
554	    runFeature: options.runFeature ?? (defaultRunFeature as RunFeatureFn<E>),
555	    workerCount: clampWorkers(options.workers, count),
556	    deadline: computeDeadline(options.globalTimeoutMs, now),
557	  };
558	}
559	
560	function computeDeadline(globalTimeoutMs: number | undefined, now: () => number): number {
561	  if (!globalTimeoutMs || globalTimeoutMs <= 0) return Number.POSITIVE_INFINITY;
562	  return now() + globalTimeoutMs;
563	}
564	
565	async function drainWorkers<E>(
566	  feature: Feature,
567	  mutations: Mutation[],
568	  results: MutationResult[],
569	  options: RunMutationsOptions<E>,
570	  config: ResolvedRun<E>,
571	  tracker: ProgressTracker,
572	): Promise<void> {
573	  let next = 0;
574	  const worker = async (): Promise<void> => {
575	    while (true) {
576	      const index = next;
577	      next += 1;
578	      if (index >= mutations.length) return;
579	      const result = await processMutation(feature, mutations[index] as Mutation, options, config);
580	      results[index] = result;
581	      tracker.record(result);
582	    }
583	  };
584	  await Promise.all(Array.from({ length: config.workerCount }, () => worker()));
585	}
586	
587	function processMutation<E>(
588	  feature: Feature,
589	  mutation: Mutation,
590	  options: RunMutationsOptions<E>,
591	  config: ResolvedRun<E>,
592	): Promise<MutationResult> {
593	  if (config.now() >= config.deadline) return Promise.resolve(abortedResult(mutation));
594	  return runOneMutation(feature, mutation, options, config);
595	}
596	
597	async function runOneMutation<E>(
598	  feature: Feature,
599	  mutation: Mutation,
600	  options: RunMutationsOptions<E>,
601	  config: ResolvedRun<E>,
602	): Promise<MutationResult> {
603	  const start = config.now();
604	  const mutated = applyMutation(feature, mutation);
605	  try {
606	    await withTimeout(
607	      config.runFeature(mutated, options.env, options.registry),
608	      options.mutantTimeoutMs,
609	    );
610	    return { mutation, status: MUTATION_SURVIVED, durationMs: config.now() - start };
611	  } catch (cause) {
612	    const status = cause instanceof MutationRunError ? MUTATION_ERROR : MUTATION_KILLED;
613	    return { mutation, status, error: messageOf(cause), durationMs: config.now() - start };
614	  }
615	}
616	
617	function applyMutation(feature: Feature, mutation: Mutation): Feature {
618	  const clone = structuredClone(feature);
619	  const row = clone.scenarios[mutation.scenario]?.examples[mutation.example];
620	  if (row !== undefined) row[mutation.key] = mutation.mutated;
621	  return clone;
622	}
623	
624	const defaultRunFeature: RunFeatureFn<unknown> = async (feature, env, registry) => {
625	  const bodies: Array<() => void | Promise<void>> = [];
626	  try {
627	    runFeatureWith(feature, env, registry, {
628	      describe: (_label, body) => body(),
629	      test: (_label, body) => {
630	        bodies.push(body);
631	      },
632	    });
633	  } catch (cause) {
634	    throw new MutationRunError(messageOf(cause));
635	  }
636	  for (const body of bodies) {
637	    await body();
638	  }
639	};
640	
641	async function withTimeout<T>(promise: Promise<T>, ms: number | undefined): Promise<T> {
642	  if (!ms || ms <= 0) return await promise;
643	  let timer: ReturnType<typeof setTimeout> | undefined;
644	  const timeout = new Promise<never>((_resolve, reject) => {
645	    timer = setTimeout(() => reject(new Error("mutant timeout")), ms);
646	  });
647	  try {
648	    return await Promise.race([promise, timeout]);
649	  } finally {
650	    if (timer !== undefined) clearTimeout(timer);
651	  }
652	}
653	
654	function clampWorkers(requested: number | undefined, mutationCount: number): number {
655	  const want = requested === undefined || requested <= 0 ? 4 : requested;
656	  return Math.min(want, mutationCount);
657	}
658	
659	function abortedResult(mutation: Mutation): MutationResult {
660	  return { mutation, status: MUTATION_ERROR, error: "global timeout", durationMs: 0 };
661	}
662	
663	function messageOf(cause: unknown): string {
664	  return cause instanceof Error ? cause.message : String(cause);
665	}
666	
667	class ProgressTracker {
668	  private completed = 0;
669	  private readonly summary: MutationSummary = { total: 0, killed: 0, survived: 0, error: 0 };
670	
671	  constructor(
672	    private readonly total: number,
673	    private readonly every: number | undefined,
674	    private readonly report: ((progress: MutationProgress) => void) | undefined,
675	  ) {}
676	
677	  record(result: MutationResult): void {
678	    this.completed += 1;
679	    this.summary.total += 1;
680	    tallyStatus(this.summary, result.status);
681	    if (this.shouldReport()) {
682	      this.report?.({
683	        completed: this.completed,
684	        total: this.total,
685	        killed: this.summary.killed,
686	        survived: this.summary.survived,
687	        error: this.summary.error,
688	      });
689	    }
690	  }
691	
692	  private shouldReport(): boolean {
693	    if (!this.reportingEnabled()) return false;
694	    const every = this.every as number;
695	    return this.completed % every === 0 || this.completed === this.total;
696	  }
697	
698	  private reportingEnabled(): boolean {
699	    return this.report !== undefined && this.every !== undefined && this.every > 0;
700	  }
701	}
702	
703	// ── Summary + exit gate ─────────────────────────────────────────────────────
704	
705	function tallyStatus(summary: MutationSummary, status: MutationStatus): void {
706	  if (status === MUTATION_KILLED) summary.killed += 1;
707	  else if (status === MUTATION_SURVIVED) summary.survived += 1;
708	  else summary.error += 1;
709	}
710	
711	export function summarize(results: MutationResult[]): MutationSummary {
712	  const summary: MutationSummary = { total: results.length, killed: 0, survived: 0, error: 0 };
713	  for (const result of results) tallyStatus(summary, result.status);
714	  return summary;
715	}
716	
717	export function mutationExitCode(summary: MutationSummary): number {
718	  return summary.survived > 0 || summary.error > 0 ? 1 : 0;
719	}
720

