// Acceptance mutation engine. Port of gospringies'
// `internal/acceptancemutation/mutator.go`, retargeted onto the #113 Gherkin
// IR + #114 generator slice.
//
// Walks Example cells, applies one typed mutation per cell, runs the mutated
// feature in-process, and classifies killed / survived / error. RNG is
// internally deterministic (same input always mutates the same way) but is
// NOT byte-identical to Go's math/rand — cross-repo parity is out of scope.
//
// Workerd-safe by construction: no node:fs / node:os / node:crypto /
// child_process. The sha256 below is a self-contained sync implementation so
// `mutateValue` stays synchronous and this whole module is unit-testable
// inside the vitest-pool-workers pool. The node CLI lives at
// `scripts/mutation-gherkin.ts`.

import type { Feature } from "./feature-ir";
import { runFeatureWith } from "./feature-runner";
import type { StepRegistry } from "./feature-step-adapter";

// ── Mutation model ──────────────────────────────────────────────────────────

export type Mutation = {
  id: string;
  path: string;
  description: string;
  original: string;
  mutated: string;
  scenario: number;
  example: number;
  key: string;
};

export const MUTATION_KILLED = "killed";
export const MUTATION_SURVIVED = "survived";
export const MUTATION_ERROR = "error";
export type MutationStatus =
  | typeof MUTATION_KILLED
  | typeof MUTATION_SURVIVED
  | typeof MUTATION_ERROR;

export type MutationResult = {
  mutation: Mutation;
  status: MutationStatus;
  error?: string;
  durationMs: number;
};

export type MutationSummary = {
  total: number;
  killed: number;
  survived: number;
  error: number;
};

export type MutationProgress = {
  completed: number;
  total: number;
  killed: number;
  survived: number;
  error: number;
};

// ── Build ─────────────────────────────────────────────────────────────────

export function buildMutations(feature: Feature): Mutation[] {
  const mutations: Mutation[] = [];
  feature.scenarios.forEach((scenario, scenarioIndex) => {
    scenario.examples.forEach((example, exampleIndex) => {
      const keys = Object.keys(example).sort();
      for (const key of keys) {
        const mutation = buildMutation(
          feature,
          scenarioIndex,
          exampleIndex,
          key,
          example[key] ?? "",
          mutations.length + 1,
        );
        if (mutation !== null) mutations.push(mutation);
      }
    });
  });
  return mutations;
}

function buildMutation(
  feature: Feature,
  scenarioIndex: number,
  exampleIndex: number,
  key: string,
  original: string,
  idNumber: number,
): Mutation | null {
  const path = `$.scenarios[${scenarioIndex}].examples[${exampleIndex}].${key}`;
  const mutated = mutateValue(path, original);
  if (mutated === original || isEquivalentMutation(feature, scenarioIndex, exampleIndex, key)) {
    return null;
  }
  return {
    id: `m${idNumber}`,
    path,
    description: `${path}: ${original} -> ${mutated}`,
    original,
    mutated,
    scenario: scenarioIndex,
    example: exampleIndex,
    key,
  };
}

// ── Equivalence-pruning hook ────────────────────────────────────────────────
//
// Feature-name-keyed registry mirroring gospringies' `equivalentMutationChecks`
// map. A rule returns `true` for an (scenario, example, key) cell that should
// be SKIPPED — typically a cell used as both setup data and the asserted value,
// where mutating both sides preserves the observed behaviour (a "null" mutant).
//
// Empty by default. Add per-feature rules as real equivalent mutants surface.
// Use `scenarioOnlyEquivalentCheck` when the rule ignores the example index.
//
//   equivalentMutationChecks["My feature"] = scenarioOnlyEquivalentCheck(
//     (scenarioIndex, key) => scenarioIndex === 2 && key === "lookup_id",
//   );

export type EquivalentMutationCheck = (
  scenarioIndex: number,
  exampleIndex: number,
  key: string,
) => boolean;

export const equivalentMutationChecks: Record<string, EquivalentMutationCheck> = {};

export function isEquivalentMutation(
  feature: Feature,
  scenarioIndex: number,
  exampleIndex: number,
  key: string,
): boolean {
  const check = equivalentMutationChecks[feature.name];
  return check?.(scenarioIndex, exampleIndex, key) ?? false;
}

export function scenarioOnlyEquivalentCheck(
  check: (scenarioIndex: number, key: string) => boolean,
): EquivalentMutationCheck {
  return (scenarioIndex, _exampleIndex, key) => check(scenarioIndex, key);
}

// ── Operators ───────────────────────────────────────────────────────────────

// Operators tried in order; the first to return non-null wins. Each takes the
// trimmed value, the original (for dither fallbacks), and the seeded RNG.
type Operator = (trimmed: string, original: string, rng: Rng) => string | null;

const OPERATORS: Operator[] = [mutateKeyword, mutateNumber, mutateDate, mutateDuration];

export function mutateValue(path: string, value: string): string {
  const trimmed = value.trim();
  const rng = deterministicRng(path, value);
  if (trimmed.includes(",")) return mutateList(path, trimmed, rng);
  for (const operator of OPERATORS) {
    const mutated = operator(trimmed, value, rng);
    if (mutated !== null) return mutated;
  }
  return dither(value, rng);
}

function mutateList(path: string, value: string, rng: Rng): string {
  const parts = value.split(",");
  const index = rng.intn(parts.length);
  const target = (parts[index] ?? "").trim();
  parts[index] = mutateValue(`${path}[${index}]`, target);
  return parts.map((part) => part.trim()).join(", ");
}

const BOOLEAN_FLIP: Record<string, string> = { true: "false", false: "true" };
const NULL_KEYWORDS = new Set(["null", "nil", "none"]);

function mutateKeyword(trimmed: string, original: string, rng: Rng): string | null {
  const lower = trimmed.toLowerCase();
  const flipped = BOOLEAN_FLIP[lower];
  if (flipped !== undefined) return flipped;
  if (NULL_KEYWORDS.has(lower)) return dither(original, rng);
  return null;
}

function mutateNumber(value: string, _original: string, rng: Rng): string | null {
  if (/^[+-]?\d+$/.test(value)) {
    return String(Number.parseInt(value, 10) + signedIntDelta(rng));
  }
  if (!/[.eE]/.test(value)) return null;
  const f = Number.parseFloat(value);
  if (!Number.isFinite(f)) return null;
  return formatFloat(f + signedFloatDelta(rng));
}

function signedIntDelta(rng: Rng): number {
  const delta = rng.intn(9) + 1;
  return rng.intn(2) === 0 ? -delta : delta;
}

function signedFloatDelta(rng: Rng): number {
  const delta = (rng.intn(900) + 100) / 100;
  return rng.intn(2) === 0 ? -delta : delta;
}

// Shortest decimal without an exponent, with fp noise stripped. Mirrors Go's
// FormatFloat(f, 'f', -1, 64) closely enough for example-cell magnitudes.
function formatFloat(n: number): string {
  const fixed = n.toFixed(10).replace(/0+$/, "").replace(/\.$/, "");
  return fixed === "-0" ? "0" : fixed;
}

const DATE_RE = /^(\d{4})-(\d{2})-(\d{2})$/;

function mutateDate(value: string, _original: string, rng: Rng): string | null {
  const match = DATE_RE.exec(value);
  if (match === null) return null;
  const date = parseUtcYmd(Number(match[1]), Number(match[2]), Number(match[3]));
  if (date === null) return null;
  date.setUTCDate(date.getUTCDate() + signedIntDelta(rng));
  return formatUtcDate(date);
}

// Reject impossible calendar dates (Go's time.Parse is strict).
function parseUtcYmd(year: number, month: number, day: number): Date | null {
  const date = new Date(Date.UTC(year, month - 1, day));
  const valid =
    date.getUTCFullYear() === year && date.getUTCMonth() === month - 1 && date.getUTCDate() === day;
  return valid ? date : null;
}

function formatUtcDate(date: Date): string {
  const y = String(date.getUTCFullYear()).padStart(4, "0");
  const m = String(date.getUTCMonth() + 1).padStart(2, "0");
  const d = String(date.getUTCDate()).padStart(2, "0");
  return `${y}-${m}-${d}`;
}

function mutateDuration(value: string, _original: string, rng: Rng): string | null {
  const ns = parseGoDuration(value);
  if (ns === null) return null;
  const added = ns + (rng.intn(9) + 1) * 1e9;
  return formatGoDuration(added);
}

function dither(value: string, rng: Rng): string {
  if (value === "") return "x";
  const runes = [...value];
  const index = rng.intn(runes.length);
  runes[index] = runes[index] === "x" ? "y" : "x";
  return runes.join("");
}

// ── Go duration parse / format (subset) ──────────────────────────────────────

const DURATION_UNITS: Record<string, number> = {
  ns: 1,
  us: 1e3,
  µs: 1e3,
  μs: 1e3,
  ms: 1e6,
  s: 1e9,
  m: 60e9,
  h: 3600e9,
};

function parseGoDuration(input: string): number | null {
  const { neg, rest } = parseSign(input);
  const ns = parseDurationBody(rest);
  if (ns === null) return null;
  return neg ? -ns : ns;
}

function parseSign(s: string): { neg: boolean; rest: string } {
  if (s.startsWith("+") || s.startsWith("-")) {
    return { neg: s[0] === "-", rest: s.slice(1) };
  }
  return { neg: false, rest: s };
}

function parseDurationBody(input: string): number | null {
  let s = input;
  if (s === "") return null;
  let total = 0;
  while (s !== "") {
    const segment = parseDurationSegment(s);
    if (segment === null) return null;
    total += segment.ns;
    s = segment.rest;
  }
  return total;
}

function parseDurationSegment(s: string): { ns: number; rest: string } | null {
  // `/^[0-9]*\.?[0-9]*/` always matches (possibly empty) → exec never null.
  const numStr = (/^[0-9]*\.?[0-9]*/.exec(s) as RegExpExecArray)[0];
  if (numStr === "" || numStr === ".") return null;
  const afterNum = s.slice(numStr.length);
  const unitMatch = /^(ns|us|µs|μs|ms|s|m|h)/.exec(afterNum);
  if (unitMatch === null) return null;
  const unit = unitMatch[1] as string;
  return {
    ns: Number.parseFloat(numStr) * (DURATION_UNITS[unit] as number),
    rest: afterNum.slice(unit.length),
  };
}

// Mutations only ever ADD whole seconds, so a mutated duration's magnitude is
// always ≥ 1s (sub-second results would need contrived negative inputs). We
// therefore format in the s / m / h range only; a rare sub-second magnitude
// renders as a fractional-second form ("0.5s"), which is still a valid Go
// duration string. Sub-second unit selection (ns/µs/ms) is intentionally
// omitted — it is unreachable from `mutateDuration`.
function formatGoDuration(ns: number): string {
  const neg = ns < 0;
  const u = Math.round(Math.abs(ns));
  if (u === 0) return "0s";
  return (neg ? "-" : "") + formatSeconds(u);
}

function formatSeconds(u: number): string {
  const frac = fmtFrac(u, 9);
  let rem = frac.value;
  let out = `${fmtInt(rem % 60)}${frac.text}s`;
  rem = Math.floor(rem / 60);
  if (rem > 0) {
    out = `${fmtInt(rem % 60)}m${out}`;
    rem = Math.floor(rem / 60);
    if (rem > 0) out = `${fmtInt(rem)}h${out}`;
  }
  return out;
}

function fmtFrac(value: number, prec: number): { text: string; value: number } {
  let v = value;
  const digits: number[] = [];
  for (let i = 0; i < prec; i++) {
    digits.push(v % 10);
    v = Math.floor(v / 10);
  }
  return { text: fracText(digits), value: v };
}

// `digits` is least-significant-first; drop the least-significant zeros, then
// render most-significant-first behind a decimal point (empty if all zero).
function fracText(digits: number[]): string {
  let start = 0;
  while (start < digits.length && digits[start] === 0) start += 1;
  if (start === digits.length) return "";
  return `.${digits.slice(start).reverse().join("")}`;
}

function fmtInt(value: number): string {
  if (value === 0) return "0";
  let v = value;
  let text = "";
  while (v > 0) {
    text = String(v % 10) + text;
    v = Math.floor(v / 10);
  }
  return text;
}

// ── Deterministic RNG: sha256(parts) → 32-bit seed → mulberry32 ──────────────

type Rng = { intn: (n: number) => number };

export function deterministicRng(...parts: string[]): Rng {
  const digest = sha256(parts.join("�"));
  // First 4 bytes, big-endian, as the mulberry32 seed.
  const seed =
    ((digest[0] as number) << 24) |
    ((digest[1] as number) << 16) |
    ((digest[2] as number) << 8) |
    (digest[3] as number);
  const next = mulberry32(seed >>> 0);
  return {
    intn: (n: number) => (n <= 0 ? 0 : Math.floor(next() * n)),
  };
}

function mulberry32(seed: number): () => number {
  let a = seed >>> 0;
  return () => {
    a = (a + 0x6d2b79f5) | 0;
    let t = Math.imul(a ^ (a >>> 15), 1 | a);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

// Self-contained synchronous SHA-256 (no node:crypto / SubtleCrypto), so the
// engine stays sync + workerd-safe. Returns the 32-byte digest.
const SHA256_K = new Uint32Array([
  0x428a2f98, 0x71374491, 0xb5c0fbcf, 0xe9b5dba5, 0x3956c25b, 0x59f111f1, 0x923f82a4, 0xab1c5ed5,
  0xd807aa98, 0x12835b01, 0x243185be, 0x550c7dc3, 0x72be5d74, 0x80deb1fe, 0x9bdc06a7, 0xc19bf174,
  0xe49b69c1, 0xefbe4786, 0x0fc19dc6, 0x240ca1cc, 0x2de92c6f, 0x4a7484aa, 0x5cb0a9dc, 0x76f988da,
  0x983e5152, 0xa831c66d, 0xb00327c8, 0xbf597fc7, 0xc6e00bf3, 0xd5a79147, 0x06ca6351, 0x14292967,
  0x27b70a85, 0x2e1b2138, 0x4d2c6dfc, 0x53380d13, 0x650a7354, 0x766a0abb, 0x81c2c92e, 0x92722c85,
  0xa2bfe8a1, 0xa81a664b, 0xc24b8b70, 0xc76c51a3, 0xd192e819, 0xd6990624, 0xf40e3585, 0x106aa070,
  0x19a4c116, 0x1e376c08, 0x2748774c, 0x34b0bcb5, 0x391c0cb3, 0x4ed8aa4a, 0x5b9cca4f, 0x682e6ff3,
  0x748f82ee, 0x78a5636f, 0x84c87814, 0x8cc70208, 0x90befffa, 0xa4506ceb, 0xbef9a3f7, 0xc67178f2,
]);

const SHA256_INIT = [
  0x6a09e667, 0xbb67ae85, 0x3c6ef372, 0xa54ff53a, 0x510e527f, 0x9b05688c, 0x1f83d9ab, 0x5be0cd19,
];

function sha256(message: string): Uint8Array {
  const padded = padMessage(new TextEncoder().encode(message));
  const dv = new DataView(padded.buffer);
  const state = Uint32Array.from(SHA256_INIT);
  for (let offset = 0; offset < padded.length; offset += 64) {
    compressBlock(state, dv, offset);
  }
  return stateToBytes(state);
}

function padMessage(bytes: Uint8Array): Uint8Array {
  const bitLen = bytes.length * 8;
  const withOne = bytes.length + 1;
  const total = withOne + ((56 - (withOne % 64) + 64) % 64) + 8;
  const padded = new Uint8Array(total);
  padded.set(bytes);
  padded[bytes.length] = 0x80;
  // 64-bit big-endian length; high word is 0 for our small inputs.
  const dv = new DataView(padded.buffer);
  dv.setUint32(total - 4, bitLen >>> 0, false);
  dv.setUint32(total - 8, Math.floor(bitLen / 0x100000000), false);
  return padded;
}

function computeSchedule(dv: DataView, offset: number): Uint32Array {
  const w = new Uint32Array(64);
  for (let i = 0; i < 16; i++) w[i] = dv.getUint32(offset + i * 4, false);
  for (let i = 16; i < 64; i++) {
    const x = w[i - 15] as number;
    const y = w[i - 2] as number;
    const s0 = rotr(x, 7) ^ rotr(x, 18) ^ (x >>> 3);
    const s1 = rotr(y, 17) ^ rotr(y, 19) ^ (y >>> 10);
    w[i] = ((w[i - 16] as number) + s0 + (w[i - 7] as number) + s1) | 0;
  }
  return w;
}

function compressBlock(state: Uint32Array, dv: DataView, offset: number): void {
  const w = computeSchedule(dv, offset);
  let a = state[0] as number;
  let b = state[1] as number;
  let c = state[2] as number;
  let d = state[3] as number;
  let e = state[4] as number;
  let f = state[5] as number;
  let g = state[6] as number;
  let hh = state[7] as number;
  for (let i = 0; i < 64; i++) {
    const s1 = rotr(e, 6) ^ rotr(e, 11) ^ rotr(e, 25);
    const ch = (e & f) ^ (~e & g);
    const t1 = (hh + s1 + ch + (SHA256_K[i] as number) + (w[i] as number)) | 0;
    const s0 = rotr(a, 2) ^ rotr(a, 13) ^ rotr(a, 22);
    const maj = (a & b) ^ (a & c) ^ (b & c);
    const t2 = (s0 + maj) | 0;
    hh = g;
    g = f;
    f = e;
    e = (d + t1) | 0;
    d = c;
    c = b;
    b = a;
    a = (t1 + t2) | 0;
  }
  const next = [a, b, c, d, e, f, g, hh];
  for (let i = 0; i < 8; i++) state[i] = ((state[i] as number) + (next[i] as number)) | 0;
}

function stateToBytes(state: Uint32Array): Uint8Array {
  const out = new Uint8Array(32);
  const outView = new DataView(out.buffer);
  for (let i = 0; i < 8; i++) outView.setUint32(i * 4, state[i] as number, false);
  return out;
}

function rotr(x: number, n: number): number {
  return (x >>> n) | (x << (32 - n));
}

// ── In-process runner ─────────────────────────────────────────────────────

// Thrown by the run hook for a generator/harness crash → classified `error`.
// Any other throw (failed assertion, missing step, timeout) → `killed`.
export class MutationRunError extends Error {}

export type RunFeatureFn<E> = (
  feature: Feature,
  env: E,
  registry: StepRegistry<E>,
) => Promise<void>;

export type RunMutationsOptions<E> = {
  registry: StepRegistry<E>;
  env: E;
  workers?: number;
  mutantTimeoutMs?: number;
  globalTimeoutMs?: number;
  progressEvery?: number;
  onProgress?: (progress: MutationProgress) => void;
  runFeature?: RunFeatureFn<E>;
  now?: () => number;
  skipPaths?: ReadonlySet<string>;
};

type ResolvedRun<E> = {
  now: () => number;
  runFeature: RunFeatureFn<E>;
  workerCount: number;
  deadline: number;
};

export async function runMutations<E>(
  feature: Feature,
  options: RunMutationsOptions<E>,
): Promise<MutationResult[]> {
  const allMutations = buildMutations(feature);
  const skipPaths = options.skipPaths;
  if (!skipPaths?.size) {
    const results: MutationResult[] = [];
    const config = resolveRun(options, allMutations.length);
    const tracker = new ProgressTracker(
      allMutations.length,
      options.progressEvery,
      options.onProgress,
    );
    await drainWorkers(feature, allMutations, results, options, config, tracker);
    return results;
  }
  const toRun = allMutations.filter((m) => !skipPaths.has(m.path));
  const runResults: MutationResult[] = [];
  const config = resolveRun(options, toRun.length);
  const tracker = new ProgressTracker(toRun.length, options.progressEvery, options.onProgress);
  await drainWorkers(feature, toRun, runResults, options, config, tracker);
  let runIdx = 0;
  return allMutations.map((m) =>
    skipPaths.has(m.path)
      ? { mutation: m, status: MUTATION_KILLED, durationMs: 0 }
      : (runResults[runIdx++] as MutationResult),
  );
}

function resolveRun<E>(options: RunMutationsOptions<E>, count: number): ResolvedRun<E> {
  const now = options.now ?? (() => Date.now());
  return {
    now,
    runFeature: options.runFeature ?? (defaultRunFeature as RunFeatureFn<E>),
    workerCount: clampWorkers(options.workers, count),
    deadline: computeDeadline(options.globalTimeoutMs, now),
  };
}

function computeDeadline(globalTimeoutMs: number | undefined, now: () => number): number {
  if (!globalTimeoutMs || globalTimeoutMs <= 0) return Number.POSITIVE_INFINITY;
  return now() + globalTimeoutMs;
}

async function drainWorkers<E>(
  feature: Feature,
  mutations: Mutation[],
  results: MutationResult[],
  options: RunMutationsOptions<E>,
  config: ResolvedRun<E>,
  tracker: ProgressTracker,
): Promise<void> {
  let next = 0;
  const worker = async (): Promise<void> => {
    while (true) {
      const index = next;
      next += 1;
      if (index >= mutations.length) return;
      const result = await processMutation(feature, mutations[index] as Mutation, options, config);
      results[index] = result;
      tracker.record(result);
    }
  };
  await Promise.all(Array.from({ length: config.workerCount }, () => worker()));
}

function processMutation<E>(
  feature: Feature,
  mutation: Mutation,
  options: RunMutationsOptions<E>,
  config: ResolvedRun<E>,
): Promise<MutationResult> {
  if (config.now() >= config.deadline) return Promise.resolve(abortedResult(mutation));
  return runOneMutation(feature, mutation, options, config);
}

async function runOneMutation<E>(
  feature: Feature,
  mutation: Mutation,
  options: RunMutationsOptions<E>,
  config: ResolvedRun<E>,
): Promise<MutationResult> {
  const start = config.now();
  const mutated = applyMutation(feature, mutation);
  try {
    await withTimeout(
      config.runFeature(mutated, options.env, options.registry),
      options.mutantTimeoutMs,
    );
    return { mutation, status: MUTATION_SURVIVED, durationMs: config.now() - start };
  } catch (cause) {
    const status = cause instanceof MutationRunError ? MUTATION_ERROR : MUTATION_KILLED;
    return { mutation, status, error: messageOf(cause), durationMs: config.now() - start };
  }
}

function applyMutation(feature: Feature, mutation: Mutation): Feature {
  const clone = structuredClone(feature);
  const row = clone.scenarios[mutation.scenario]?.examples[mutation.example];
  if (row !== undefined) row[mutation.key] = mutation.mutated;
  return clone;
}

const defaultRunFeature: RunFeatureFn<unknown> = async (feature, env, registry) => {
  const bodies: Array<() => void | Promise<void>> = [];
  try {
    runFeatureWith(feature, env, registry, {
      describe: (_label, body) => body(),
      test: (_label, body) => {
        bodies.push(body);
      },
    });
  } catch (cause) {
    throw new MutationRunError(messageOf(cause));
  }
  for (const body of bodies) {
    await body();
  }
};

async function withTimeout<T>(promise: Promise<T>, ms: number | undefined): Promise<T> {
  if (!ms || ms <= 0) return await promise;
  let timer: ReturnType<typeof setTimeout> | undefined;
  const timeout = new Promise<never>((_resolve, reject) => {
    timer = setTimeout(() => reject(new Error("mutant timeout")), ms);
  });
  try {
    return await Promise.race([promise, timeout]);
  } finally {
    if (timer !== undefined) clearTimeout(timer);
  }
}

function clampWorkers(requested: number | undefined, mutationCount: number): number {
  const want = requested === undefined || requested <= 0 ? 4 : requested;
  return Math.min(want, mutationCount);
}

function abortedResult(mutation: Mutation): MutationResult {
  return { mutation, status: MUTATION_ERROR, error: "global timeout", durationMs: 0 };
}

function messageOf(cause: unknown): string {
  return cause instanceof Error ? cause.message : String(cause);
}

class ProgressTracker {
  private completed = 0;
  private readonly summary: MutationSummary = { total: 0, killed: 0, survived: 0, error: 0 };

  constructor(
    private readonly total: number,
    private readonly every: number | undefined,
    private readonly report: ((progress: MutationProgress) => void) | undefined,
  ) {}

  record(result: MutationResult): void {
    this.completed += 1;
    this.summary.total += 1;
    tallyStatus(this.summary, result.status);
    if (this.shouldReport()) {
      this.report?.({
        completed: this.completed,
        total: this.total,
        killed: this.summary.killed,
        survived: this.summary.survived,
        error: this.summary.error,
      });
    }
  }

  private shouldReport(): boolean {
    if (!this.reportingEnabled()) return false;
    const every = this.every as number;
    return this.completed % every === 0 || this.completed === this.total;
  }

  private reportingEnabled(): boolean {
    return this.report !== undefined && this.every !== undefined && this.every > 0;
  }
}

// ── Summary + exit gate ─────────────────────────────────────────────────────

function tallyStatus(summary: MutationSummary, status: MutationStatus): void {
  if (status === MUTATION_KILLED) summary.killed += 1;
  else if (status === MUTATION_SURVIVED) summary.survived += 1;
  else summary.error += 1;
}

export function summarize(results: MutationResult[]): MutationSummary {
  const summary: MutationSummary = { total: results.length, killed: 0, survived: 0, error: 0 };
  for (const result of results) tallyStatus(summary, result.status);
  return summary;
}

export function mutationExitCode(summary: MutationSummary): number {
  return summary.survived > 0 || summary.error > 0 ? 1 : 0;
}

