fn find_error_nodes(node: tree_sitter::Node, source: &str, errors: &mut Vec<String>) {
    if node.is_error() || node.is_missing() {
        let start = node.start_position();
        let end = node.end_position();
        let text = &source[node.start_byte()..node.end_byte().min(source.len())];
        errors.push(format!(
            "{}:{}-{}:{} kind={:?} text={:?}",
            start.row + 1, start.column, end.row + 1, end.column, node.kind(), &text[..text.len().min(80)]
        ));
    }
    let mut cursor = node.walk();
    for child in node.children(&mut cursor) {
        find_error_nodes(child, source, errors);
    }
}

